#include "sensor.h"
#include "i2c.h"

#define MAX_RETRIES 3
#define TEMP_ERROR INT16_MIN

int16_t read_temperature(void) {
    uint8_t buf[2];
    for (int attempt = 0; attempt < MAX_RETRIES; attempt++) {
        if (i2c_read(SENSOR_ADDR, TEMP_REG, buf, 2) == 0) {
            int16_t raw = (buf[0] << 8) | buf[1];
            if (raw != (int16_t)0xFFFF) {
                return raw;
            }
        }
    }
    return TEMP_ERROR;
}

float get_temperature_celsius(void) {
    int16_t raw = read_temperature();
    if (raw == TEMP_ERROR) {
        return -999.0f;  /* error sentinel */
    }
    return raw * 0.0625f;
}
